import Marquee from "react-fast-marquee";
import { motion } from "framer-motion";

const MovingGallery = () => {
  const videos = [
    "/assets/videos/cooking.mp4",
    "/assets/videos/vid2.mp4",
    "/assets/videos/vid3.mp4",
    "/assets/videos/vid5.mp4",
    "/assets/videos/vid6.mp4"
  ];

  const images = [
    "/assets/amb.jpg",
    "/assets/apr.jpg",
    "/assets/ballent.jpg",
    "/assets/bl.jpg",
    "/assets/bn.jpg",
    "/assets/dj.jpg",
    "/assets/dri.jpg",
    "/assets/f1.jpg",
    "/assets/grp.jpg",
    "/assets/nod.jpg",
    "/assets/pic.jpg",
    "/assets/piz.jpg"
  ];

  return (
    <section className="relative py-24 bg-black overflow-hidden">
      {/* Section Title */}
      <motion.div className="text-center mb-20" initial={{ opacity: 0 }} whileInView={{ opacity: 1 }}>
        <span className="font-accent inline-block text-gold text-sm tracking-[0.25em] uppercase px-8 py-3 bg-black rounded-full border border-gold">
          Moments
        </span>
        <h2 className="font-heading text-5xl md:text-6xl text-white mt-8 leading-tight">
          Corridor Gallery
        </h2>
      </motion.div>

      {/* Video Portrait Marquee */}
      <motion.div className="w-full mb-16" initial={{ opacity: 0 }} whileInView={{ opacity: 1 }}>
        <Marquee speed={25} gradient={false} pauseOnHover>
          {videos.concat(videos).map((src, index) => (
            <video
              key={index}
              src={src}
              className="mx-[1px] w-[210px] h-[370px] object-cover rounded-2xl shadow-2xl border border-black/50"
              muted
              autoPlay
              loop
              playsInline
              preload="auto"
            />
          ))}
        </Marquee>
      </motion.div>

      {/* Images Marquee LTR */}
      <motion.div className="w-full mb-16" initial={{ opacity: 0 }} whileInView={{ opacity: 1 }}>
        <Marquee speed={65} gradient={false} pauseOnHover>
          {images.map((src, index) => (
            <motion.img
              key={index}
              src={src}
              alt=""
              className="mx-[1px] w-[300px] h-[210px] object-cover rounded-xl shadow-xl border-2 border-black grayscale group-hover:grayscale-0 hover:scale-110 transition-all duration-400"
              loading="eager"
              whileHover={{ scale: 1.03 }}
            />
          ))}
        </Marquee>
      </motion.div>

      {/* Images Marquee RTL */}
      <motion.div className="w-full" initial={{ opacity: 0 }} whileInView={{ opacity: 1 }}>
        <Marquee speed={65} direction="right" gradient={false} pauseOnHover>
          {images.slice(0, 10).map((src, index) => (
            <motion.img
              key={"rtl-" + index}
              src={src}
              alt=""
              className="mx-[1px] w-[300px] h-[210px] object-cover rounded-xl shadow-xl border-2 border-black grayscale group-hover:grayscale-0 hover:scale-110 transition-all duration-400"
              loading="eager"
              whileHover={{ scale: 1.03 }}
            />
          ))}
        </Marquee>
      </motion.div>
    </section>
  );
};

export default MovingGallery;
